parameters.jsCode:
const shipment = $('Create Shipment').first().json.data;
const rates = $('Get Rates').first().json.data || [];
const order = $('Save Draft Order').first().json;

const formattedRates = rates.map(r => ({
  rate_id: r.rate_id,
  carrier: r.carrier_name,
  carrier_logo: r.carrier_logo || null,
  amount: r.amount,
  delivery_time: r.delivery_time || r.estimated_days || 'N/A',
  pickup_time: r.pickup_time || 'N/A',
  cod_available: r.cash_on_delivery || false
}));

return [{
  json: {
    success: true,
    shipment_id: shipment.shipment_id,
    order_id: order.id,
    rates: formattedRates,
    message: formattedRates.length > 0
      ? `Found ${formattedRates.length} delivery option(s).`
      : 'No carriers available for this route. Try adjusting the addresses.'
  }
}];

const order = $input.first()?.json ?? {};
const input = $('Incoming Tool Request').first().json;

if (!order.id) {
  return [{
    json: {
      success: false,
      error: 'order_not_found',
      shipment_id: input.shipment_id || null,
      message: input.shipment_id
        ? 'No dispatch order found for this user and shipment.'
        : 'No dispatch order found for this user.'
    }
  }];
}

return [{ json: order }];

const order = $input.first()?.json ?? {};
const input = $('Incoming Tool Request').first().json;

if (!order.id) {
  return [{
    json: {
      success: false,
      error: 'order_not_found',
      shipment_id: input.shipment_id || null,
      message: 'No dispatch order found for this user and shipment.'
    }
  }];
}

const pickupAddress = typeof order.pickup_address === 'string'
  ? JSON.parse(order.pickup_address)
  : order.pickup_address || {};

return [{
  json: {
    ...order,
    pickup_phone: pickupAddress.phone || ''
  }
}];

return [{
  json: {
    success: false,
    error: 'speedy_payment_failed',
    message: 'Speedy wallet payment failed. User can retry or switch to cash on delivery (COD).',
    shipment_id: $('Incoming Tool Request').first().json.shipment_id
  }
}];

const result = $('Finalize Dispatch Confirmation').first().json || {};
const pickup = $('Arrange Pickup').first().json.data || {};
const input = $('Incoming Tool Request').first().json || {};

return [{
  json: {
    success: true,
    partial: false,
    shipment_id: result.shipment_id || input.shipment_id || null,
    order_number: result.order_number || input.order_number || null,
    carrier: result.carrier_name || pickup.carrier_name || 'Assigned carrier',
    amount: result.amount ?? pickup.amount ?? input.amount ?? null,
    tracking_number: result.tracking_number || pickup.tracking_number || null,
    tracking_url: result.tracking_url || pickup.tracking_url || null,
    pickup_time: pickup.pickup_time || pickup.pickup_eta || 'Will be communicated by carrier',
    delivery_time: pickup.delivery_time || pickup.delivery_eta || 'See tracking for updates',
    payment_method: input.payment_method || null,
    status: 'confirmed',
    customer_order_updated: result.customer_order_updated === true,
    message: 'Dispatch confirmed! Carrier will pick up the package.'
  }
}];

const order = $input.first()?.json ?? {};
const input = $('Incoming Tool Request').first().json;

if (!order.id) {
  return [{
    json: {
      success: false,
      error: 'order_not_found',
      shipment_id: input.shipment_id || null,
      message: input.shipment_id
        ? 'No dispatch order found for this user and shipment.'
        : 'No dispatch order found for this user.'
    }
  }];
}

return [{ json: order }];

const terminal = $('Get Shipment Status').first().json.data || {};
const local    = $('Get Order from table_3').first().json || {};

return [{
  json: {
    success:         true,
    shipment_id:     local.shipment_id,
    carrier:         local.carrier_name       || terminal.carrier_name    || 'N/A',
    status:          terminal.status          || local.status,
    tracking_number: local.tracking_number    || terminal.tracking_number || null,
    tracking_url:    local.tracking_url       || terminal.tracking_url    || null,
    amount:          local.amount,
    payment_method:  local.payment_method,
    events:          terminal.events          || terminal.tracking_events || [],
    last_updated:    terminal.updated_at      || local.updated_at,
    pickup_address:  local.pickup_address,
    delivery_address: local.delivery_address
  }
}];

const orders = $('List Recent Orders').all().map(item => {
  const o = item.json;
  return {
    shipment_id:     o.shipment_id,
    carrier:         o.carrier_name || 'Pending',
    status:          o.status,
    amount:          o.amount,
    payment:         o.payment_method || 'N/A',
    tracking_number: o.tracking_number || null,
    destination:     o.delivery_address
      ? (typeof o.delivery_address === 'string'
          ? JSON.parse(o.delivery_address)
          : o.delivery_address).city
      : 'N/A',
    date: o.created_at
  };
});

return [{
  json: {
    success: true,
    total:   orders.length,
    orders:  orders,
    message: orders.length > 0
      ? `Found ${orders.length} recent dispatch order(s).`
      : 'No dispatch orders found. User has not made any deliveries yet.'
  }
}];

// ── Packaging auto-selection based on item weight ────────────────
//
// Three packaging types pre-created on Terminal Africa account:
//   Soft Package  → envelopes, fliers, soft pouches   (< 0.5 kg)
//   Standard Box  → Terminal default, most shipments  (0.5 – 5 kg)
//   Large Box     → bulky / heavy items               (> 5 kg)
//
// TO SET UP:
//   1. Log into Terminal Africa dashboard
//   2. Go to Settings → Packaging
//   3. Create the three packaging entries below (or use existing ones)
//   4. Replace the packaging_id values with your actual IDs
//   5. The Terminal default box ID is PA-PT95DUJGH8FRKSO0 — use that
//      for STANDARD_BOX if you haven't created your own yet

const PACKAGING = {
  soft:     'PA-SOFT_PACKAGING_ID',      // < 0.5 kg  — envelope / flier
  standard: 'PA-PT95DUJGH8FRKSO0',      // 0.5–5 kg  — Terminal default box
  large:    'PA-LARGE_BOX_ID'           // > 5 kg    — large box
};

const input    = $('Incoming Tool Request').first().json;
const weightKg = parseFloat(input.item_weight_kg) || 1;

let packagingId;
if (weightKg < 0.5) {
  packagingId = PACKAGING.soft;
} else if (weightKg <= 5) {
  packagingId = PACKAGING.standard;
} else {
  packagingId = PACKAGING.large;
}

// Pass through all original fields plus resolved packaging ID
return [{
  json: {
    ...input,
    resolved_packaging_id: packagingId,
    resolved_weight_kg:    weightKg
  }
}];

const result = $('Finalize Dispatch Confirmation').first().json || {};
const input = $('Incoming Tool Request').first().json || {};

return [{
  json: {
    success: true,
    partial: true,
    warning: 'customer_order_not_linked',
    shipment_id: result.shipment_id || input.shipment_id || null,
    order_number: result.order_number || input.order_number || null,
    carrier: result.carrier_name || 'Assigned carrier',
    amount: result.amount ?? input.amount ?? null,
    tracking_number: result.tracking_number || null,
    tracking_url: result.tracking_url || null,
    payment_method: input.payment_method || null,
    status: 'confirmed',
    customer_order_updated: false,
    message: 'Dispatch was confirmed with the courier, but I could not link it back to a customer order. Please verify the order number for this shipment.'
  }
}];
